// v7.52: 轮询进度函数
var advPollInterval = null;

function pollAdvProgress(taskId) {
    var progressEl = document.getElementById('advProgress');
    var pollUrl = '/api/v1/advanced/detect/status/' + taskId;
    
    // 清除之前的轮询
    if (advPollInterval) clearInterval(advPollInterval);
    
    // v7.53: 添加去重逻辑，避免重复输出
    var lastStep = '';
    
    advPollInterval = setInterval(function() {
        fetch(pollUrl)
        .then(r => r.json())
        .then(data => {
            if (data.success) {
                // v7.52: 后端返回的字段直接在根级别（没有task包裹）
                var progress = data.progress || 0;
                var step = data.current_step || 'running';
                var status = data.status || 'running';
                
                // v7.52: 更新进度显示（N/M格式）
                var completedItems = data.completed_items || 0;
                var totalItems = data.total_items || 0;
                if (progressEl) {
                    if (totalItems > 0) {
                        progressEl.textContent = currentAdvTest + ' (' + completedItems + '/' + totalItems + ')';
                    } else {
                        progressEl.textContent = currentAdvTest + ' ' + progress.toFixed(0) + '%';
                    }
                }
                
                // v7.53: 实时输出当前检测端点（去重：只在步骤变化时输出）
                if (step && step !== 'running' && step !== 'completed' && step !== lastStep) {
                    var lastResult = data.last_result || '';
                    addAdvOutput(lastResult === 'pass' ? 'success' : (lastResult === 'failed' ? 'error' : 'info'), 
                        '检测端点: ' + step + '...' + (lastResult || ''));
                    lastStep = step;
                }
                
                // v7.53: 检查是否完成（使用getElementById获取按钮，因为是局部变量）
                if (status === 'completed') {
                    clearInterval(advPollInterval);
                    addAdvOutput('success', '测试完成');
                    document.getElementById('btnAdvRun').disabled = false;
                    document.getElementById('btnAdvStop').disabled = true;
                    // 获取最终结果
                    fetchResult(taskId);
                } else if (status === 'failed') {
                    clearInterval(advPollInterval);
                    addAdvOutput('error', '测试失败: ' + step);
                    document.getElementById('btnAdvRun').disabled = false;
                    document.getElementById('btnAdvStop').disabled = true;
                    if (progressEl) progressEl.textContent = currentAdvTest + ' 失败';
                }
            }
        })
        .catch(e => {
            console.error('Poll error:', e);
        });
    }, 1000); // 每1秒轮询一次
}

function fetchResult(taskId) {
    var resultUrl = '/api/v1/advanced/detect/result/' + taskId;
    fetch(resultUrl)
    .then(r => r.json())
    .then(data => {
        if (data.success && data.results) {
            // v7.52: 从总结果中取当前测试类型的结果
            var testResult = data.results[currentAdvTest] || data.results;
            renderAdvResult(testResult);
            // 更新进度显示完成数量
            var progressEl = document.getElementById('advProgress');
            if (progressEl) {
                var funcs = testResult.functions || testResult;
                var count = Object.keys(funcs).length;
                progressEl.textContent = currentAdvTest + ' 完成(' + count + ')';
            }
        }
    })
    .catch(e => {
        addAdvOutput('error', '获取结果失败: ' + e.message);
    });
}
</script>

