            var progressEl = document.getElementById('advProgress');
            if (progressEl) {
                var funcs = testResult.functions || testResult;
                var count = Object.keys(funcs).length;
                progressEl.textContent = currentAdvTest + ' 完成(' + count + ')';
            }
        }
    })
    .catch(e => {
        addAdvOutput('error', '获取结果失败: ' + e.message);
    });
}
